class APMTransaction:
    """Represents a single APM transaction."""
    
    def __init__(self, name: str, transaction_type: str = "request"):
        self.name = name
        self.transaction_type = transaction_type
        self.transaction_id = id(self)
        self.start_time = time.time()
        self.end_time = None
        self.duration_ms = None
        self.result = None
        self.spans = []
        self.context = {}
        self.tags = {}
        self.errors = []
        self.stack_traces = []
    
    def end(self, result: str = "success"):
        self.end_time = time.time()
        self.duration_ms = (self.end_time - self.start_time) * 1000
        self.result = result
    
    def to_dict(self) -> Dict:
        return {
            "transaction_id": self.transaction_id,
            "name": self.name,
            "type": self.transaction_type,
            "start_time": datetime.fromtimestamp(self.start_time).isoformat(),
            "end_time": datetime.fromtimestamp(self.end_time).isoformat() if self.end_time else None,
            "duration_ms": self.duration_ms,
            "result": self.result,
            "spans_count": len(self.spans),
            "errors_count": len(self.errors),
            "context": self.context,
            "tags": self.tags,
            "spans": [s.to_dict() for s in self.spans],
            "errors": self.errors,
            "stack_traces": self.stack_traces,
        }


class APMSpan:
    """Represents a span within a transaction."""
    
    def __init__(self, name: str, span_type: str, subtype: str = None, action: str = None):
        self.name = name
        self.span_type = span_type
        self.subtype = subtype
        self.action = action
        self.span_id = id(self)
        self.start_time = time.time()
        self.end_time = None
        self.duration_ms = None
        self.context = {}
        self.stack_trace = None
    
    def end(self):
        self.end_time = time.time()
        self.duration_ms = (self.end_time - self.start_time) * 1000
    
    def to_dict(self) -> Dict:
        return {
            "span_id": self.span_id,
            "name": self.name,
            "type": self.span_type,
            "subtype": self.subtype,
            "action": self.action,
            "start_time": datetime.fromtimestamp(self.start_time).isoformat(),
            "duration_ms": self.duration_ms,
            "context": self.context,
            "stack_trace": self.stack_trace,
        }


class APMAgent:
    """
    Application Performance Monitoring Agent.
    Captures transactions, spans, errors, SQL queries, and stack traces.
    """
    
    def __init__(self, config: Dict[str, Any] = None):
        self.config = config or {}
        self.service_name = self.config.get("SERVICE_NAME", "my-python-app")
        self.environment = self.config.get("ENVIRONMENT", "development")
        self.server_url = self.config.get("SERVER_URL", "http://localhost:8200")
        self.capture_body = self.config.get("CAPTURE_BODY", "all")
        self.capture_headers = self.config.get("CAPTURE_HEADERS", True)
        self.collect_sql_queries = self.config.get("COLLECT_SQL_QUERIES", True)
        self.stack_trace_limit = self.config.get("STACK_TRACE_LIMIT", 50)
        self.transaction_sample_rate = self.config.get("TRANSACTION_SAMPLE_RATE", 1.0)
        self.slow_query_threshold_ms = self.config.get("SLOW_QUERY_THRESHOLD_MS", 500)
        
        self._current_transaction: Optional[APMTransaction] = None
        self._transactions_store = []
        self._errors_store = []
        self._metrics_store = []
        
        # Elastic APM client (if available)
        self._elastic_client = None
        self._init_elastic_apm()
        
        logger.info(
            f"APM Agent initialized - Service: {self.service_name}, "
            f"Environment: {self.environment}, Server: {self.server_url}"
        )
    
    def _init_elastic_apm(self):
        """Try to initialize Elastic APM client."""
        try:
            import elasticapm
            self._elastic_client = elasticapm.Client(
                service_name=self.service_name,
                server_url=self.server_url,
                environment=self.environment,
                capture_body=self.capture_body,
                capture_headers=self.capture_headers,
                transaction_sample_rate=self.transaction_sample_rate,
                collect_unsampled_transactions=True,
                auto_log_stacks=True,
                stack_trace_limit=self.stack_trace_limit,
            )
            logger.info("Elastic APM client initialized successfully")
        except ImportError:
            logger.warning(
                "elastic-apm not installed. Using built-in APM tracking. "
                "Install with: pip install elastic-apm"
            )
        except Exception as e:
            logger.warning(f"Failed to initialize Elastic APM client: {e}")
    
    def begin_transaction(self, name: str, transaction_type: str = "request") -> APMTransaction:
        """Start a new transaction."""
        transaction = APMTransaction(name, transaction_type)
        self._current_transaction = transaction
        
        if self._elastic_client:
            try:
                import elasticapm
                elasticapm.set_transaction_name(name)
            except Exception:
                pass
        
        logger.debug(f"Transaction started: {name} (type: {transaction_type})")
        return transaction
    
    def end_transaction(self, result: str = "success"):
        """End the current transaction."""
        if self._current_transaction:
            self._current_transaction.end(result)
            self._transactions_store.append(self._current_transaction)
            
            # Log transaction summary
            tx = self._current_transaction
            logger.info(
                f"Transaction completed: {tx.name} | "
                f"Duration: {tx.duration_ms:.2f}ms | "
                f"Result: {tx.result} | "
                f"Spans: {len(tx.spans)} | "
                f"Errors: {len(tx.errors)}"
            )
            
            # Check for slow transactions
            if tx.duration_ms > 1000:
                logger.warning(
                    f"SLOW TRANSACTION: {tx.name} took {tx.duration_ms:.2f}ms"
                )
            
            self._current_transaction = None
    
    @contextmanager
    def transaction(self, name: str, transaction_type: str = "request"):
        """Context manager for transactions."""
        tx = self.begin_transaction(name, transaction_type)
        try:
            yield tx
            self.end_transaction("success")
        except Exception as e:
            self.capture_exception(e)
            self.end_transaction("error")
            raise
    
    def begin_span(self, name: str, span_type: str, subtype: str = None, 
                   action: str = None) -> APMSpan:
        """Start a new span within the current transaction."""
        span = APMSpan(name, span_type, subtype, action)
        
        # Capture stack trace for the span
        span.stack_trace = self._capture_stack_trace()
        
        logger.debug(f"Span started: {name} (type: {span_type})")
        return span
    
    def end_span(self, span: APMSpan):
        """End a span and attach it to the current transaction."""
        span.end()
        
        if self._current_transaction:
            self._current_transaction.spans.append(span)
        
        logger.debug(
            f"Span completed: {span.name} | Duration: {span.duration_ms:.2f}ms"
        )
        
        # Check for slow spans
        if span.span_type == "db" and span.duration_ms > self.slow_query_threshold_ms:
            logger.warning(
                f"SLOW QUERY: {span.name} took {span.duration_ms:.2f}ms | "
                f"Context: {json.dumps(span.context, default=str)}"
            )
    
    @contextmanager
    def span(self, name: str, span_type: str, subtype: str = None, action: str = None):
        """Context manager for spans."""
        s = self.begin_span(name, span_type, subtype, action)
        try:
            yield s
            self.end_span(s)
        except Exception as e:
            s.context["error"] = str(e)
            self.end_span(s)
            raise
    
    def capture_exception(self, exception: Exception = None):
        """Capture and record an exception."""
        if exception is None:
            import sys
            exception = sys.exc_info()[1]
        
        error_info = {
            "timestamp": datetime.utcnow().isoformat(),
            "exception_type": type(exception).__name__,
            "message": str(exception),
            "stack_trace": traceback.format_exc(),
            "full_stack": self._capture_stack_trace(),
        }
        
        self._errors_store.append(error_info)
        
        if self._current_transaction:
            self._current_transaction.errors.append(error_info)
            self._current_transaction.stack_traces.append(
                traceback.format_exc()
            )
        
        if self._elastic_client:
            try:
                self._elastic_client.capture_exception()
            except Exception:
                pass
        
        logger.error(
            f"Exception captured: {type(exception).__name__}: {exception}\n"
            f"{traceback.format_exc()}"
        )
    
    def capture_message(self, message: str, level: str = "info"):
        """Capture a custom message."""
        msg_info = {
            "timestamp": datetime.utcnow().isoformat(),
            "message": message,
            "level": level,
        }
        
        if self._current_transaction:
            self._current_transaction.context.setdefault("messages", []).append(msg_info)
        
        logger.log(getattr(logging, level.upper(), logging.INFO), f"APM Message: {message}")
    
    def set_transaction_context(self, context: Dict):
        """Set additional context on the current transaction."""
        if self._current_transaction:
            self._current_transaction.context.update(context)
    
    def tag_transaction(self, **tags):
        """Add tags to the current transaction."""
        if self._current_transaction:
            self._current_transaction.tags.update(tags)
    
    def _capture_stack_trace(self) -> list:
        """Capture the current stack trace."""
        stack = traceback.extract_stack()
        return [
            {
                "filename": frame.filename,
                "line_number": frame.lineno,
                "function": frame.name,
                "code": frame.line,
            }
            for frame in stack[-self.stack_trace_limit:]
            if "apm" not in frame.filename.lower()  # Filter out APM frames
        ]
    
    def get_metrics_summary(self) -> Dict:
        """Get a summary of collected metrics."""
        total_transactions = len(self._transactions_store)
        if total_transactions == 0:
            return {"total_transactions": 0}
        
        durations = [
            t.duration_ms for t in self._transactions_store 
            if t.duration_ms is not None
        ]
        error_count = sum(
            1 for t in self._transactions_store if t.result == "error"
        )
        
        return {
            "total_transactions": total_transactions,
            "total_errors": len(self._errors_store),
            "error_rate": error_count / total_transactions if total_transactions else 0,
            "avg_duration_ms": sum(durations) / len(durations) if durations else 0,
            "min_duration_ms": min(durations) if durations else 0,
            "max_duration_ms": max(durations) if durations else 0,
            "p95_duration_ms": sorted(durations)[int(len(durations) * 0.95)] if durations else 0,
            "total_spans": sum(len(t.spans) for t in self._transactions_store),
        }
    
    def get_slow_transactions(self, threshold_ms: float = 1000) -> list:
        """Get transactions slower than the threshold."""
        return [
            t.to_dict() for t in self._transactions_store
            if t.duration_ms and t.duration_ms > threshold_ms
        ]
    
    def get_recent_errors(self, limit: int = 10) -> list:
        """Get recent errors."""
        return self._errors_store[-limit:]
    
    def close(self):
        """Cleanup APM agent."""
        if self._elastic_client:
            try:
                self._elastic_client.close()
            except Exception:
                pass
        logger.info("APM Agent closed")


