class SQLQueryTracker:
    """Tracks SQL queries with timing and explain plans."""
    
    def __init__(self, apm_agent: APMAgent):
        self.apm_agent = apm_agent
        self.queries = []
    
    @contextmanager
    def track_query(self, query: str, params: tuple = None, db_type: str = "sql"):
        """Track a SQL query as an APM span."""
        sanitized_query = self._sanitize_query(query)
        
        with self.apm_agent.span(
            name=sanitized_query[:100],
            span_type="db",
            subtype=db_type,
            action="query"
        ) as span:
            span.context = {
                "db": {
                    "type": db_type,
                    "statement": query,
                    "params": str(params) if params else None,
                }
            }
            
            query_record = {
                "query": query,
                "params": params,
                "start_time": time.time(),
                "db_type": db_type,
            }
            
            try:
                yield span
                query_record["success"] = True
            except Exception as e:
                query_record["success"] = False
                query_record["error"] = str(e)
                raise
            finally:
                query_record["end_time"] = time.time()
                query_record["duration_ms"] = (
                    query_record["end_time"] - query_record["start_time"]
                ) * 1000
                self.queries.append(query_record)
    
    def _sanitize_query(self, query: str) -> str:
        """Sanitize SQL query for display (remove sensitive data)."""
        import re
        # Replace string literals
        sanitized = re.sub(r"'[^']*'", "'?'", query)
        # Replace numeric literals
        sanitized = re.sub(r'\b\d+\b', '?', sanitized)
        return sanitized.strip()
    
    def get_slow_queries(self, threshold_ms: float = None) -> list:
        """Get queries slower than threshold."""
        threshold = threshold_ms or self.apm_agent.slow_query_threshold_ms
        return [q for q in self.queries if q.get("duration_ms", 0) > threshold]
    
    def get_query_stats(self) -> Dict:
        """Get query statistics."""
        if not self.queries:
            return {"total_queries": 0}
        
        durations = [q["duration_ms"] for q in self.queries if "duration_ms" in q]
        return {
            "total_queries": len(self.queries),
            "failed_queries": sum(1 for q in self.queries if not q.get("success")),
            "avg_duration_ms": sum(durations) / len(durations) if durations else 0,
            "max_duration_ms": max(durations) if durations else 0,
            "slow_queries": len(self.get_slow_queries()),
        }


