class HTTPTracker:
    """Tracks HTTP requests and responses."""
    
    def __init__(self, apm_agent: APMAgent):
        self.apm_agent = apm_agent
    
    def track_request(self, method: str, url: str, headers: Dict = None, 
                      body: Any = None) -> Dict:
        """Capture request data."""
        request_data = {
            "method": method,
            "url": url,
            "timestamp": datetime.utcnow().isoformat(),
        }
        
        if self.apm_agent.capture_headers and headers:
            # Filter sensitive headers
            safe_headers = {
                k: v for k, v in headers.items()
                if k.lower() not in ("authorization", "cookie", "x-api-key")
            }
            request_data["headers"] = safe_headers
        
        if self.apm_agent.capture_body == "all" and body:
            request_data["body"] = self._safe_body(body)
        
        return request_data
    
    def track_response(self, status_code: int, headers: Dict = None, 
                       body: Any = None, duration_ms: float = None) -> Dict:
        """Capture response data."""
        response_data = {
            "status_code": status_code,
            "timestamp": datetime.utcnow().isoformat(),
        }
        
        if duration_ms is not None:
            response_data["duration_ms"] = duration_ms
        
        if self.apm_agent.capture_headers and headers:
            response_data["headers"] = dict(headers)
        
        if self.apm_agent.capture_body == "all" and body:
            response_data["body"] = self._safe_body(body)
        
        return response_data
    
    def _safe_body(self, body: Any, max_length: int = 10000) -> str:
        """Safely convert body to string with size limit."""
        try:
            if isinstance(body, bytes):
                body_str = body.decode("utf-8", errors="replace")
            elif isinstance(body, str):
                body_str = body
            else:
                body_str = json.dumps(body, default=str)
            
            if len(body_str) > max_length:
                return body_str[:max_length] + "... [TRUNCATED]"
            return body_str
        except Exception:
            return "[BODY_CAPTURE_FAILED]"


