# Decorator-based APM instrumentation
# ============================================================

def apm_trace(name: str = None, span_type: str = "code", 
              subtype: str = "custom", capture_args: bool = False):
    """Decorator to trace function execution as APM span."""
    def decorator(func: Callable):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            trace_name = name or f"{func.__module__}.{func.__qualname__}"
            
            if not hasattr(wrapper, '_apm_agent') or wrapper._apm_agent is None:
                return func(*args, **kwargs)
            
            agent = wrapper._apm_agent
            
            with agent.span(trace_name, span_type, subtype) as span:
                if capture_args:
                    span.context["args"] = str(args)[:500]
                    span.context["kwargs"] = str(kwargs)[:500]
                
                result = func(*args, **kwargs)
                
                span.context["result_type"] = type(result).__name__
                return result
        
        wrapper._apm_agent = None
        return wrapper
    return decorator


def set_apm_agent_on_decorated(module_globals: Dict, agent: APMAgent):
    """Set the APM agent on all decorated functions in a module."""
    for name, obj in module_globals.items():
        if callable(obj) and hasattr(obj, '_apm_agent'):
            obj._apm_agent = agent


