class FlaskAPMMiddleware:
    """Flask middleware for automatic APM instrumentation."""
    
    def __init__(self, app, apm_agent: APMAgent):
        self.app = app
        self.apm_agent = apm_agent
        self.http_tracker = HTTPTracker(apm_agent)
        
        # Try to use elastic-apm Flask integration
        self._setup_elastic_flask(app)
        
        # Register before/after request hooks
        app.before_request(self._before_request)
        app.after_request(self._after_request)
        app.teardown_request(self._teardown_request)
    
    def _setup_elastic_flask(self, app):
        """Setup Elastic APM Flask integration if available."""
        try:
            from elasticapm.contrib.flask import ElasticAPM
            apm_config = {
                'SERVICE_NAME': self.apm_agent.service_name,
                'SERVER_URL': self.apm_agent.server_url,
                'ENVIRONMENT': self.apm_agent.environment,
                'CAPTURE_BODY': self.apm_agent.capture_body,
                'CAPTURE_HEADERS': self.apm_agent.capture_headers,
                'DEBUG': True,
            }
            app.config['ELASTIC_APM'] = apm_config
            ElasticAPM(app)
            logger.info("Elastic APM Flask integration enabled")
        except ImportError:
            logger.info("Using custom Flask APM middleware")
        except Exception as e:
            logger.warning(f"Failed to setup Elastic APM Flask integration: {e}")
    
    def _before_request(self):
        """Called before each request."""
        from flask import request, g
        
        g.apm_start_time = time.time()
        
        transaction_name = f"{request.method} {request.path}"
        g.apm_transaction = self.apm_agent.begin_transaction(
            transaction_name, "request"
        )
        
        # Capture request data
        request_data = self.http_tracker.track_request(
            method=request.method,
            url=request.url,
            headers=dict(request.headers),
            body=request.get_data(as_text=True) if request.content_length else None,
        )
        
        self.apm_agent.set_transaction_context({
            "request": request_data,
            "user_agent": request.user_agent.string,
            "remote_addr": request.remote_addr,
        })
    
    def _after_request(self, response):
        """Called after each request."""
        from flask import request, g
        
        duration_ms = (time.time() - g.get('apm_start_time', time.time())) * 1000
        
        # Capture response data
        response_data = self.http_tracker.track_response(
            status_code=response.status_code,
            headers=dict(response.headers),
            body=response.get_data(as_text=True) if response.content_length else None,
            duration_ms=duration_ms,
        )
        
        self.apm_agent.set_transaction_context({"response": response_data})
        
        # Tag with status code category
        if response.status_code >= 500:
            self.apm_agent.tag_transaction(error="server_error")
            result = "HTTP 5xx"
        elif response.status_code >= 400:
            self.apm_agent.tag_transaction(error="client_error")
            result = "HTTP 4xx"
        else:
            result = f"HTTP {response.status_code}"
        
        self.apm_agent.end_transaction(result)
        
        # Add APM headers to response
        response.headers['X-APM-Transaction-Duration'] = f"{duration_ms:.2f}ms"
        
        return response
    
    def _teardown_request(self, exception=None):
        """Called on request teardown (even on errors)."""
        if exception:
            self.apm_agent.capture_exception(exception)
            self.apm_agent.end_transaction("error")


