class SQLAlchemyAPMIntegration:
    """Instruments SQLAlchemy with APM tracking."""
    
    def __init__(self, apm_agent: APMAgent, engine=None):
        self.apm_agent = apm_agent
        self.sql_tracker = SQLQueryTracker(apm_agent)
        
        if engine:
            self.instrument_engine(engine)
    
    def instrument_engine(self, engine):
        """Add event listeners to SQLAlchemy engine."""
        try:
            from sqlalchemy import event
            
            event.listen(engine, "before_cursor_execute", self._before_cursor_execute)
            event.listen(engine, "after_cursor_execute", self._after_cursor_execute)
            event.listen(engine, "handle_error", self._handle_error)
            
            logger.info("SQLAlchemy engine instrumented with APM")
        except ImportError:
            logger.warning("SQLAlchemy not installed")
        except Exception as e:
            logger.warning(f"Failed to instrument SQLAlchemy: {e}")
    
    def _before_cursor_execute(self, conn, cursor, statement, parameters, 
                                context, executemany):
        """Called before SQL execution."""
        conn.info.setdefault('apm_query_start', []).append(time.time())
        
        span = self.apm_agent.begin_span(
            name=statement[:100],
            span_type="db",
            subtype="sql",
            action="query"
        )
        span.context = {
            "db": {
                "type": "sql",
                "statement": statement,
                "params": str(parameters)[:1000] if parameters else None,
            }
        }
        conn.info.setdefault('apm_spans', []).append(span)
    
    def _after_cursor_execute(self, conn, cursor, statement, parameters, 
                               context, executemany):
        """Called after SQL execution."""
        spans = conn.info.get('apm_spans', [])
        if spans:
            span = spans.pop()
            
            # Add result info
            if cursor.description:
                span.context["db"]["rows_affected"] = cursor.rowcount
            
            self.apm_agent.end_span(span)
    
    def _handle_error(self, exception_context):
        """Called on SQL error."""
        self.apm_agent.capture_exception(exception_context.original_exception)


# ============================================================
# External HTTP Call Tracker
# ============================================================

class ExternalHTTPTracker:
    """Tracks external HTTP calls."""
    
    def __init__(self, apm_agent: APMAgent):
        self.apm_agent = apm_agent
    
    @contextmanager
    def track_call(self, method: str, url: str, service_name: str = None):
        """Track an external HTTP call."""
        span_name = f"{method.upper()} {url}"
        
        with self.apm_agent.span(
            name=span_name,
            span_type="external",
            subtype="http",
            action=method.lower()
        ) as span:
            span.context = {
                "http": {
                    "method": method.upper(),
                    "url": url,
                },
                "destination": {
                    "service": service_name or url.split('/')[2] if '/' in url else url,
                }
            }
            yield span
    
    def instrument_requests_library(self):
        """Monkey-patch the requests library for automatic tracking."""
        try:
            import requests
            original_request = requests.Session.request
            tracker = self
            
            def patched_request(self_session, method, url, **kwargs):
                with tracker.track_call(method, url) as span:
                    response = original_request(self_session, method, url, **kwargs)
                    span.context["http"]["status_code"] = response.status_code
                    span.context["http"]["response_size"] = len(response.content)
                    return response
            
            requests.Session.request = patched_request
            logger.info("requests library instrumented with APM")
        except ImportError:
            logger.warning("requests library not installed")


# ============================================================
# APM Dashboard / Reporting
# ============================================================

class APMDashboard:
    """Simple APM dashboard for viewing metrics."""
    
    def __init__(self, apm_agent: APMAgent, sql_tracker: SQLQueryTracker = None):
        self.apm_agent = apm_agent
        self.sql_tracker = sql_tracker
        self.system_metrics = SystemMetricsCollector(apm_agent)
    
    def get_dashboard_data(self) -> Dict:
        """Get comprehensive dashboard data."""
        return {
            "service": {
                "name": self.apm_agent.service_name,
                "environment": self.apm_agent.environment,
            },
            "transactions": self.apm_agent.get_metrics_summary(),
            "slow_transactions": self.apm_agent.get_slow_transactions(),
            "recent_errors": self.apm_agent.get_recent_errors(),
            "sql": self.sql_tracker.get_query_stats() if self.sql_tracker else None,
            "slow_queries": (
                self.sql_tracker.get_slow_queries() if self.sql_tracker else None
            ),
            "system_metrics": self.system_metrics.collect(),
        }
    
    def print_summary(self):
        """Print a formatted summary to console."""
        data = self.get_dashboard_data()
        
        print("\n" + "=" * 70)
        print(f"  APM Dashboard - {data['service']['name']} ({data['service']['environment']})")
        print("=" * 70)
        
        tx = data["transactions"]
        print(f"\n📊 TRANSACTIONS:")
        print(f"   Total: {tx.get('total_transactions', 0)}")
        print(f"   Errors: {tx.get('total_errors', 0)}")
        print(f"   Error Rate: {tx.get('error_rate', 0):.1%}")
        print(f"   Avg Duration: {tx.get('avg_duration_ms', 0):.2f}ms")
        print(f"   Min Duration: {tx.get('min_duration_ms', 0):.2f}ms")
        print(f"   Max Duration: {tx.get('max_duration_ms', 0):.2f}ms")
        print(f"   P95 Duration: {tx.get('p95_duration_ms', 0):.2f}ms")
        print(f"   Total Spans: {tx.get('total_spans', 0)}")
        
        if data.get("sql"):
            sql = data["sql"]
            print(f"\n🔍 SQL QUERIES:")
            print(f"   Total: {sql.get('total_queries', 0)}")
            print(f"   Failed: {sql.get('failed_queries', 0)}")
            print(f"   Avg Duration: {sql.get('avg_duration_ms', 0):.2f}ms")
            print(f"   Max Duration: {sql.get('max_duration_ms', 0):.2f}ms")
            print(f"   Slow Queries: {sql.get('slow_queries', 0)}")
        
        if data.get("slow_transactions"):
            print(f"\n🐌 SLOW TRANSACTIONS:")
            for st in data["slow_transactions"][:5]:
                print(f"   - {st['name']}: {st['duration_ms']:.2f}ms")
        
        if data.get("recent_errors"):
            print(f"\n❌ RECENT ERRORS:")
            for err in data["recent_errors"][:5]:
                print(f"   - [{err.get('exception_type')}] {err.get('message', '')[:80]}")
        
        sys_metrics = data.get("system_metrics", {})
        if "cpu" in sys_metrics:
            print(f"\n💻 SYSTEM METRICS:")
            print(f"   CPU: {sys_metrics['cpu']['percent']}%")
            print(f"   Memory: {sys_metrics['memory']['percent']}% "
                  f"({sys_metrics['memory']['used_mb']:.0f}MB / "
                  f"{sys_metrics['memory']['total_mb']:.0f}MB)")
            if "process" in sys_metrics:
                print(f"   Process Memory: {sys_metrics['process']['memory_mb']:.1f}MB")
                print(f"   Threads: {sys_metrics['process']['threads']}")
        
        print("\n" + "=" * 70)


# ============================================================
# Example Flask Application with Full APM Integration
# ============================================================

def create_app():
    """Create and configure the Flask application with APM."""
    from flask import Flask, jsonify, request
    
    app = Flask(__name__)
    
    # APM Configuration
    apm_config = {
        "SERVICE_NAME": os.getenv("APM_SERVICE_NAME", "demo-python-app"),
        "ENVIRONMENT": os.getenv("APM_ENVIRONMENT", "development"),
        "SERVER_URL": os.getenv("APM_SERVER_URL", "http://localhost:8200"),
        "CAPTURE_BODY": "all",
        "CAPTURE_HEADERS": True,
        "COLLECT_SQL_QUERIES": True,
        "STACK_TRACE_LIMIT": 50,
        "TRANSACTION_SAMPLE_RATE": 1.0,
        "SLOW_QUERY_THRESHOLD_MS": 100,
    }
    
    # Initialize APM
    apm_agent = APMAgent(apm_config)
    sql_tracker = SQLQueryTracker(apm_agent)
    http_tracker = ExternalHTTPTracker(apm_agent)
    dashboard = APMDashboard(apm_agent, sql_tracker)
    
    # Setup Flask middleware
    FlaskAPMMiddleware(app, apm_agent)
    
    # Store references on app
    app.apm_agent = apm_agent
    app.sql_tracker = sql_tracker
    app.apm_dashboard = dashboard
    
    # ---- Routes ----
    
    @app.route("/")
    def index():
        return jsonify({
            "service": apm_config["SERVICE_NAME"],
            "status": "healthy",
            "timestamp": datetime.utcnow().isoformat(),
        })
    
    @app.route("/api/users")
    def get_users():
        """Simulated endpoint with DB query tracking."""
        with sql_tracker.track_query(
            "SELECT id, name, email FROM users WHERE active = %s ORDER BY name",
            params=(True,),
            db_type="postgresql"
        ) as span:
            # Simulate DB query
            time.sleep(0.05)
            span.context["db"]["rows_returned"] = 42
        
        return jsonify({
            "users": [
                {"id": 1, "name": "Alice", "email": "alice@example.com"},
                {"id": 2, "name": "Bob", "email": "bob@example.com"},
            ],
            "total": 2,
        })
    
    @app.route("/api/users/<int:user_id>")
    def get_user(user_id):
        """Simulated endpoint with multiple spans."""
        # DB query span
        with sql_tracker.track_query(
            "SELECT * FROM users WHERE id = %s",
            params=(user_id,),
            db_type="postgresql"
        ):
            time.sleep(0.02)
        
        # Cache lookup span
        with apm_agent.span("cache:user:lookup", "cache", "redis", "get"):
            time.sleep(0.005)
        
        if user_id > 100:
            apm_agent.tag_transaction(user_type="premium")
        
        return jsonify({
            "id": user_id,
            "name": f"User {user_id}",
            "email": f"user{user_id}@example.com",
        })
    
    @app.route("/api/slow")
    def slow_endpoint():
        """Deliberately slow endpoint for testing."""
        with apm_agent.span("heavy_computation", "code", "custom"):
            time.sleep(0.5)  # Simulate heavy work
        
        with sql_tracker.track_query(
            "SELECT * FROM large_table WHERE complex_condition = %s "
            "JOIN another_table ON ... ORDER BY ...",
            params=("value",),
            db_type="postgresql"
        ):
            time.sleep(0.3)  # Simulate slow query
        
        return jsonify({"result": "done", "note": "This was intentionally slow"})
    
    @app.route("/api/error")
    def error_endpoint():
        """Endpoint that raises an error."""
        raise ValueError("This is a test error for APM monitoring")
    
    @app.route("/api/external-call")
    def external_call():
        """Endpoint making external HTTP calls."""
        with http_tracker.track_call("GET", "https://api.example.com/data", "example-api") as span:
            time.sleep(0.1)  # Simulate external call
            span.context["http"]["status_code"] = 200
            span.context["http"]["response_size"] = 1024
        
        return jsonify({"external_data": "fetched successfully"})
    
    @app.route("/api/complex-operation")
    def complex_operation():
        """Endpoint demonstrating nested spans."""
        results = {}
        
        # Step 1: Validate input
        with apm_agent.span("validate_input", "code", "validation"):
            time.sleep(0.01)
            results["validation"] = "passed"
        
        # Step 2: Query database
        with sql_tracker.track_query(
            "SELECT * FROM orders WHERE user_id = %s AND status = %s",
            params=(1, "active"),
            db_type="postgresql"
        ):
            time.sleep(0.03)
            results["db_query"] = "completed"
        
        # Step 3: Process data
        with apm_agent.span("process_data", "code", "business_logic"):
            time.sleep(0.02)
            
            # Nested cache operation
            with apm_agent.span("cache_check", "cache", "redis", "get"):
                time.sleep(0.005)
            
            results["processing"] = "completed"
        
        # Step 4: External API call
        with http_tracker.track_call("POST", "https://notifications.example.com/send") as span:
            time.sleep(0.05)
            span.context["http"]["status_code"] = 201
            results["notification"] = "sent"
        
        # Step 5: Update database
        with sql_tracker.track_query(
            "UPDATE orders SET processed = true WHERE user_id = %s",
            params=(1,),
            db_type="postgresql"
        ):
            time.sleep(0.02)
            results["db_update"] = "completed"
        
        apm_agent.capture_message("Complex operation completed successfully")
        
        return jsonify(results)
    
    @app.route("/apm/dashboard")
    def apm_dashboard_view():
        """APM Dashboard endpoint."""
        return jsonify(dashboard.get_dashboard_data())
    
    @app.route("/apm/metrics")
    def apm_metrics():
        """APM metrics summary."""
        return jsonify(apm_agent.get_metrics_summary())
    
    @app.route("/apm/transactions")
    def apm_transactions():
        """List recent transactions."""
        limit = request.args.get("limit", 20, type=int)
        transactions = [
            t.to_dict() for t in apm_agent._transactions_store[-limit:]
        ]
        return jsonify({"transactions": transactions})
    
    @app.route("/apm/errors")
    def apm_errors():
        """List recent errors."""
        return jsonify({"errors": apm_agent.get_recent_errors()})
    
    @app.route("/apm/slow-queries")
    def apm_slow_queries():
        """List slow SQL queries."""
        return jsonify({"slow_queries": sql_tracker.get_slow_queries()})
    
    # Error handlers
    @app.errorhandler(404)
    def not_found(e):
        return jsonify({"error": "Not found"}), 404
    
    @app.errorhandler(500)
    def internal_error(e):
        apm_agent.capture_exception(e)
        return jsonify({"error": "Internal server error"}), 500
    
    @app.errorhandler(Exception)
    def handle_exception(e):
        apm_agent.capture_exception(e)
        return jsonify({
            "error": type(e).__name__,
            "message": str(e),
        }), 500
    
    return app


# ============================================================
# Standalone Usage Example (without Flask)
# ============================================================

def standalone_demo():
    """Demonstrate APM usage without Flask."""
    print("\n🚀 APM Standalone Demo\n")
    
    # Initialize APM
    apm_config = {
        "SERVICE_NAME": "standalone-demo",
        "ENVIRONMENT": "demo",
        "CAPTURE_BODY": "all",
        "SLOW_QUERY_THRESHOLD_MS": 100,
    }
    
    agent = APMAgent(apm_config)
    sql_tracker = SQLQueryTracker(agent)
    http_tracker = ExternalHTTPTracker(agent)
    dashboard = APMDashboard(agent, sql_tracker)
    
    # --- Transaction 1: Normal operation ---
    with agent.transaction("process_order", "background"):
        agent.tag_transaction(order_id="12345", customer="acme")
        
        # Simulate DB queries
        with sql_tracker.track_query(
            "SELECT * FROM products WHERE id IN (1, 2, 3)",
            db_type="postgresql"
        ):
            time.sleep(0.03)
        
        with agent.span("calculate_total", "code", "business_logic"):
            time.sleep(0.02)
        
        with sql_tracker.track_query(
            "INSERT INTO orders (customer_id, total) VALUES (%s, %s)",
            params=(42, 99.99),
            db_type="postgresql"
        ):
            time.sleep(0.02)
        
        with http_tracker.track_call("POST", "https://payment.example.com/charge") as span:
            time.sleep(0.05)
            span.context["http"]["status_code"] = 200
    
    # --- Transaction 2: Slow operation ---
    with agent.transaction("generate_report", "background"):
        with sql_tracker.track_query(
            "SELECT * FROM analytics WHERE date BETWEEN %s AND %s "
            "GROUP BY category ORDER BY total DESC",
            params=("2024-01-01", "2024-12-31"),
            db_type="postgresql"
        ):
            time.sleep(0.2)  # Slow query
        
        with agent.span("render_pdf", "code", "rendering"):
            time.sleep(0.3)
    
    # --- Transaction 3: Error case ---
    try:
        with agent.transaction("failing_operation", "background"):
            with agent.span("risky_operation", "code"):
                raise RuntimeError("Something went wrong!")
    except RuntimeError:
        pass  # Error is captured by APM
    
    # --- Transaction 4: Multiple fast operations ---
    for i in range(5):
        with agent.transaction(f"quick_task_{i}", "background"):
            time.sleep(0.01)
    
    # Print dashboard
    dashboard.print_summary()
    
    # Print detailed transaction data
    print("\n📋 DETAILED TRANSACTION LOG:")
    print("-" * 70)
    for tx in agent._transactions_store:
        tx_data = tx.to_dict()
        print(f"\n  Transaction: {tx_data['name']}")
        print(f"  Duration: {tx_data['duration_ms']:.2f}ms | Result: {tx_data['result']}")
        if tx_data['tags']:
            print(f"  Tags: {tx_data['tags']}")
        for span_data in tx_data['spans']:
            print(f"    └─ Span: {span_data['name'][:60]} "
                  f"({span_data['type']}/{span_data.get('subtype', '')}) "
                  f"- {span_data['duration_ms']:.2f}ms")
        if tx_data['errors']:
            for err in tx_data['errors']:
                print(f"    ⚠️  Error: {err['exception_type']}: {err['message']}")
    
    # Cleanup
    agent.close()
    
    return agent


