            print("   - GET  /                      - Health check")
            print("   - GET  /api/users              - List users (with DB tracking)")
            print("   - GET  /api/users/<id>         - Get user (with cache tracking)")
            print("   - GET  /api/slow               - Slow endpoint")
            print("   - GET  /api/error              - Error endpoint")
            print("   - GET  /api/external-call      - External HTTP call")
            print("   - GET  /api/complex-operation  - Complex multi-span operation")
            print("   - GET  /apm/dashboard          - APM Dashboard (JSON)")
            print("   - GET  /apm/metrics            - APM Metrics")
